using PX.Data;
using PX.Data.BQL;
using PX.Objects.AR;

namespace HeritageFabrics.AR
{
    public sealed class CustomerExt : PXCacheExtension<Customer>
    {
        public static bool IsActive() => true;

        #region UsrDisablePayLink
        public abstract class usrDisablePayLink : BqlBool.Field<usrDisablePayLink> { }

        [PXDBBool]
        [PXDefault(false, PersistingCheck = PXPersistingCheck.Nothing)]
        [PXUIField(DisplayName = "Exclude from Payment Link Processing")]
        public bool? UsrDisablePayLink { get; set; }
        #endregion
    }
}

using System;
using PX.Data;
using PX.Objects.AR;
using PX.Objects.CS;

namespace HeritageFabrics.AR
{
    public class ARInvoiceEntry_PayLink_Extension : PXGraphExtension<ARInvoiceEntry>
    {
        public static bool IsActive() => true;

        protected void _(Events.RowSelected<ARInvoice> e)
        {
            if (e.Row == null) return;

            bool disablePayLink = IsPayLinkDisabledForCustomer(e.Row.CustomerID);

            if (Base.Actions.Contains("SendPaymentLink"))
            {
                Base.Actions["SendPaymentLink"].SetEnabled(!disablePayLink);
            }

            if (Base.Actions.Contains("sendPayLink"))
            {
                Base.Actions["sendPayLink"].SetEnabled(!disablePayLink);
            }
        }

        private bool IsPayLinkDisabledForCustomer(int? customerID)
        {
            if (customerID == null) return false;

            Customer customer = PXSelect<Customer,
                Where<Customer.bAccountID, Equal<Required<Customer.bAccountID>>>>
                .Select(Base, customerID);

            if (customer == null) return false;

            // Check 1: Explicit per-customer flag
            CustomerExt ext = customer.GetExtension<CustomerExt>();
            if (ext?.UsrDisablePayLink == true) return true;

            // Check 2: Terms description contains "factor"
            if (!string.IsNullOrEmpty(customer.TermsID))
            {
                Terms terms = PXSelect<Terms,
                    Where<Terms.termsID, Equal<Required<Terms.termsID>>>>
                    .Select(Base, customer.TermsID);
                if (terms?.Descr != null &&
                    terms.Descr.IndexOf("factor", StringComparison.OrdinalIgnoreCase) >= 0)
                    return true;
            }

            return false;
        }
    }
}

using PX.Data;
using PX.Data.BQL;
using PX.Objects.SO;

namespace HeritageFabrics.SO
{
    public sealed class SOOrderExt : PXCacheExtension<SOOrder>
    {
        public static bool IsActive() => true;

        #region UsrHubSpotDealId
        public abstract class usrHubSpotDealId : BqlString.Field<usrHubSpotDealId> { }

        [PXDBString(50, IsUnicode = true)]
        [PXUIField(DisplayName = "HubSpot Order ID", Enabled = false)]
        public string UsrHubSpotDealId { get; set; }
        #endregion
    }
}

Sql.CDATA:
IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('POOrder') AND name = 'UsrExpArrivalDate')
    ALTER TABLE POOrder ADD UsrExpArrivalDate datetime NULL;

IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('POOrder') AND name = 'UsrActArrivalDate')
    ALTER TABLE POOrder ADD UsrActArrivalDate datetime NULL;

IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('POLine') AND name = 'UsrExpArrivalDate')
    ALTER TABLE POLine ADD UsrExpArrivalDate datetime NULL;

IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('POLine') AND name = 'UsrActArrivalDate')
    ALTER TABLE POLine ADD UsrActArrivalDate datetime NULL;

IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('SOOrder') AND name = 'UsrHubSpotDealId')
    ALTER TABLE SOOrder ADD UsrHubSpotDealId nvarchar(50) NULL;

IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('BAccount') AND name = 'UsrDisablePayLink')
    ALTER TABLE BAccount ADD UsrDisablePayLink bit NULL;
